def process_file(slug, summary_bullets, toc_links, body_sections, takeaway_bullets, quiz_questions):
    filepath = os.path.join(TUTORIALS_DIR, slug, 'index.html')
    if not os.path.exists(filepath):
        print(f"Error: {filepath} not found!")
        return False
        
    with open(filepath, 'r', encoding='utf-8') as f:
        content = f.read()

    # Replacements
    # Summary bullets
    if '<!-- [[SUMMARY_BULLETS]] -->' in content:
        content = content.replace('<!-- [[SUMMARY_BULLETS]] -->', summary_bullets.strip())
    elif '[[SUMMARY_BULLETS]]' in content:
        content = content.replace('[[SUMMARY_BULLETS]]', summary_bullets.strip())
        
    # TOC Links
    if '<!-- [[TOC_LINKS]] -->' in content:
        content = content.replace('<!-- [[TOC_LINKS]] -->', toc_links.strip())
    elif '[[TOC_LINKS]]' in content:
        content = content.replace('[[TOC_LINKS]]', toc_links.strip())
        
    # Body sections
    if '<!-- [[BODY_SECTIONS]] -->' in content:
        content = content.replace('<!-- [[BODY_SECTIONS]] -->', body_sections.strip())
    elif '[[BODY_SECTIONS]]' in content:
        content = content.replace('[[BODY_SECTIONS]]', body_sections.strip())
        
    # Takeaway bullets
    if '<!-- [[TAKEAWAY_BULLETS]] -->' in content:
        content = content.replace('<!-- [[TAKEAWAY_BULLETS]] -->', takeaway_bullets.strip())
    elif '[[TAKEAWAY_BULLETS]]' in content:
        content = content.replace('[[TAKEAWAY_BULLETS]]', takeaway_bullets.strip())
        
    # Quiz questions
    if '<!-- [[QUIZ_QUESTIONS]] -->' in content:
        content = content.replace('<!-- [[QUIZ_QUESTIONS]] -->', quiz_questions.strip())
    elif '[[QUIZ_QUESTIONS]]' in content:
        content = content.replace('[[QUIZ_QUESTIONS]]', quiz_questions.strip())

    # Write back
    with open(filepath, 'w', encoding='utf-8') as f:
        f.write(content)
        
    print(f"Successfully processed {slug}")
    return True

